detailed_optimizations.code_changes:
将每个 t 内的 3 个 2D 更新按 tile 执行（保持语义：ey 依赖旧 hz；ex 依赖旧 hz；hz 依赖更新后的 ex/ey）。示例（伪代码，需处理边界）：

const int Ti=64, Tj=256; // 依据缓存/NUMA 调参
for (t=0; t<TMAX; ++t) {
  // ey[0][:]
  #pragma omp parallel for simd
  for (j=0;j<NY;++j) ey[0][j]=_fict_[t];

  for (int ii=1; ii<NX; ii+=Ti) {
    int iend = (ii+Ti<NX)? ii+Ti : NX;
    for (int jj=0; jj<NY; jj+=Tj) {
      int jend = (jj+Tj<NY)? jj+Tj : NY;

      // 1) ey tile (i in [ii,iend), j in [jj,jend)
      #pragma omp parallel for collapse(2)
      for (int i=ii;i<iend;++i)
        for (int j=jj;j<jend;++j)
          ey[i][j] = ey[i][j] - (DATA_TYPE)0.5*(hz[i][j]-hz[i-1][j]);

      // 2) ex tile (note j starts at 1)
      int jj2 = (jj==0)? 1 : jj;
      #pragma omp parallel for collapse(2)
      for (int i=ii-1;i<iend;++i) { // 需要覆盖 hz 更新会用到的 ex[i][j] 与 ex[i][j+1]
        if (i<0 || i>=NX) continue;
        for (int j=jj2;j<jend;++j)
          ex[i][j] = ex[i][j] - (DATA_TYPE)0.5*(hz[i][j]-hz[i][j-1]);
      }

      // 3) hz tile (i in [ii-1,iend-1), j in [jj,jend-1)
      int i0 = (ii-1<0)? 0 : ii-1;
      int i1 = (iend-1<NX-1)? iend-1 : NX-1;
      int j1 = (jend-1<NY-1)? jend-1 : NY-1;
      #pragma omp parallel for collapse(2)
      for (int i=i0;i<i1;++i)
        for (int j=jj;j<j1;++j)
          hz[i][j] = hz[i][j] - (DATA_TYPE)0.7*( (ex[i][j+1]-ex[i][j]) + (ey[i+1][j]-ey[i][j]) );
    }
  }
}

要点：tile 内按依赖顺序执行 ey->ex->hz；tile 边界需额外覆盖 i-1、j+1 的 halo（上面用扩大循环范围示意）。

对每个 2D 循环加 OpenMP，并优先并行 i 维（行块）以减少线程间写冲突与提升局部性：

for (t=0; t<TMAX; ++t) {
  #pragma omp parallel for simd
  for (j=0;j<NY;++j) ey[0][j]=_fict_[t];

  #pragma omp parallel for collapse(2) schedule(static)
  for (i=1;i<NX;++i)
    for (j=0;j<NY;++j)
      ey[i][j] -= (DATA_TYPE)0.5*(hz[i][j]-hz[i-1][j]);

  #pragma omp parallel for collapse(2) schedule(static)
  for (i=0;i<NX;++i)
    for (j=1;j<NY;++j)
      ex[i][j] -= (DATA_TYPE)0.5*(hz[i][j]-hz[i][j-1]);

  #pragma omp parallel for collapse(2) schedule(static)
  for (i=0;i<NX-1;++i)
    for (j=0;j<NY-1;++j)
      hz[i][j] -= (DATA_TYPE)0.7*((ex[i][j+1]-ex[i][j])+(ey[i+1][j]-ey[i][j]));
}

并配合：OMP_PROC_BIND=close, OMP_PLACES=cores；NUMA 机器上 first-touch 初始化（init_array 也并行化）。
